UPDATE post SET content = #{content}, delivery_type = #{deliveryType}, grade = #{grade}, marking = #{marking},
                price = #{price}, risk_level = #{riskLevel}, size = #{size}, sport = #{sport},
                status = #{status}, team = #{team}, title = #{title}, uniform_name = #{uniformName},
                view_count = #{viewCount}, wish_count = #{wishCount}, seller_id = #{sellerId}
WHERE post_id = #{postId}
